    vector<int> earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = 1, latest = 1;
        while (true) {
            int m = n;
            int f = firstPlayer;
            int s = secondPlayer;
            if (f > s) swap(f, s);
            bool meet = false;
            int round = 0;
            while (m > 1) {
                round++;
                int mid = (m + 1) / 2;
                if (f + s == m + 1) {
                    meet = true;
                    break;
                }
                if (s <= mid) {
                    f = (f + 1) / 2;
